input.command:
powershell -Command '
$lines = Get-Content "C:\Users\Administrator\Desktop\dsc_gn7\can pe 자료\20250905_STD_DB_CAR_R2.0_2024_FD_B2_25.08.01.dbc" -Encoding UTF8
$inBlock = $false
$result = @()
for ($i = 0; $i -lt $lines.Count; $i++) {
    if ($lines[$i] -match "^BO_ 1179 ") {
        $inBlock = $true
        $result += $lines[$i]
        continue
    }
    if ($inBlock) {
        if ($lines[$i] -match "^ SG_ ") {
            $result += $lines[$i]
        } else {
            break
        }
    }
}
$result -join "`n"
